{
  "extends": ["config:base"],
  "packageRules": [
    {
      "matchUpdateTypes": ["patch"],
      "automerge": false,
      "schedule": ["every week on monday"],
      "groupName": "all patch updates"
    },
    {
      "matchUpdateTypes": ["minor", "major"],
      "automerge": false,
      "schedule": ["every month"]
    }
  ],
  "lockFileMaintenance": {
    "enabled": true,
    "schedule": ["every week on monday"]
  }
}
